contracts/NFT.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.10;

import "@openzeppelin/contracts/token/ERC721/ERC721.sol";
import "@openzeppelin/contracts/token/ERC721/extensions/ERC721URIStorage.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/utils/Counters.sol";

/**
 * @title ArtBlockNFT
 * @dev 基于ERC721C标准的数字藏品合约
 */
contract ArtBlockNFT is ERC721, ERC721URIStorage, Ownable {
    using Counters for Counters.Counter;
    Counters.Counter private _tokenIdCounter;

    // 藏品版税信息
    struct RoyaltyInfo {
        address creator;
        uint96 royaltyPercentage; // 版税百分比，以0.01%为单位，例如500代表5%
    }

    // 存储每个token的版税信息
    mapping(uint256 => RoyaltyInfo) private _tokenRoyaltyInfo;

    constructor() ERC721("ArtBlockNFT", "ABNFT") {}

    /**
     * @dev 铸造新的NFT
     * @param to 接收NFT的地址
     * @param uri NFT的元数据URI
     * @param royaltyPercentage 版税百分比，以0.01%为单位，例如500代表5%
     */
    function mint(address to, string memory uri, uint96 royaltyPercentage) public onlyOwner returns (uint256) {
        uint256 tokenId = _tokenIdCounter.current();
        _tokenIdCounter.increment();
        _safeMint(to, tokenId);
        _setTokenURI(tokenId, uri);

        // 设置版税信息
        _tokenRoyaltyInfo[tokenId] = RoyaltyInfo({
            creator: to,
            royaltyPercentage: royaltyPercentage
        });

        return tokenId;
    }

    /**
     * @dev 获取NFT的版税信息
     * @param tokenId NFT的token ID
     * @param salePrice 销售价格
     * @return receiver 版税接收地址
     * @return royaltyAmount 版税金额
     */
    function royaltyInfo(uint256 tokenId, uint256 salePrice) external view returns (address receiver, uint256 royaltyAmount) {
        RoyaltyInfo memory info = _tokenRoyaltyInfo[tokenId];
        receiver = info.creator;
        royaltyAmount = (salePrice * info.royaltyPercentage) / 10000;
    }

    /**
     * @dev 批量获取NFT的版税信息
     * @param tokenIds NFT的token ID数组
     * @param salePrices 销售价格数组
     * @return receivers 版税接收地址数组
     * @return royaltyAmounts 版税金额数组
     */
    function royaltyInfoBatch(uint256[] memory tokenIds, uint256[] memory salePrices) external view returns (address[] memory receivers, uint256[] memory royaltyAmounts) {
        require(tokenIds.length == salePrices.length, "Input arrays must have the same length");

        receivers = new address[](tokenIds.length);
        royaltyAmounts = new uint256[](tokenIds.length);

        for (uint256 i = 0; i < tokenIds.length; i++) {
            RoyaltyInfo memory info = _tokenRoyaltyInfo[tokenIds[i]];
            receivers[i] = info.creator;
            royaltyAmounts[i] = (salePrices[i] * info.royaltyPercentage) / 10000;
        }
    }

    /**
     * @dev 获取NFT的创造者
     * @param tokenId NFT的token ID
     * @return creator NFT的创造者地址
     */
    function getCreator(uint256 tokenId) external view returns (address creator) {
        return _tokenRoyaltyInfo[tokenId].creator;
    }

    /**
     * @dev 获取NFT的版税百分比
     * @param tokenId NFT的token ID
     * @return percentage 版税百分比，以0.01%为单位，例如500代表5%
     */
    function getRoyaltyPercentage(uint256 tokenId) external view returns (uint96 percentage) {
        return _tokenRoyaltyInfo[tokenId].royaltyPercentage;
    }

    /**
     * @dev 更新NFT的版税信息
     * @param tokenId NFT的token ID
     * @param newRoyaltyPercentage 新的版税百分比，以0.01%为单位，例如500代表5%
     */
    function updateRoyaltyInfo(uint256 tokenId, uint96 newRoyaltyPercentage) external {
        require(_isApprovedOrOwner(_msgSender(), tokenId), "Caller is not owner nor approved");
        _tokenRoyaltyInfo[tokenId].royaltyPercentage = newRoyaltyPercentage;
    }

    // 修复supportsInterface函数的继承冲突
    function supportsInterface(bytes4 interfaceId)
        public
        view
        override(ERC721, ERC721URIStorage)
        returns (bool)
    {
        return super.supportsInterface(interfaceId);
    }

    // The following functions are overrides required by Solidity.
    function _burn(uint256 tokenId) internal override(ERC721, ERC721URIStorage) {
        super._burn(tokenId);
    }

    function tokenURI(uint256 tokenId) public view override(ERC721, ERC721URIStorage) returns (string memory) {
        return super.tokenURI(tokenId);
    }
}

contracts/NFTMarketplace.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.10;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/security/ReentrancyGuard.sol";
import "./NFT.sol";

/**
 * @title ArtBlockNFTMarketplace
 * @dev 数字藏品交易市场合约
 */
contract ArtBlockNFTMarketplace is Ownable, ReentrancyGuard {
    // 平台费用比例，以0.01%为单位，例如200代表2%
    uint96 public platformFeePercentage = 200;

    // 争议期时长（秒）
    uint256 public disputePeriod = 72 hours;

    // 平台收益地址
    address public platformWallet;

    // 稳定币地址（用于平台收益自动兑换）
    address public stablecoinAddress;

    // 交易状态
    enum SaleStatus { Active, Completed, Canceled, Dispute }

    // 交易信息
    struct Sale {
        uint256 tokenId;
        address nftContract;
        address seller;
        address buyer;
        uint256 price;
        SaleStatus status;
        uint256 createdAt;
        uint256 updatedAt;
        uint256 disputeEndTime;
    }

    // 存储所有交易
    mapping(uint256 => Sale) public sales;
    uint256 public saleCount;

    // 事件
    event ItemListed(uint256 indexed saleId, address indexed nftContract, uint256 indexed tokenId, address seller, uint256 price);
    event ItemSold(uint256 indexed saleId, address indexed nftContract, uint256 indexed tokenId, address seller, address buyer, uint256 price);
    event ItemCanceled(uint256 indexed saleId, address indexed nftContract, uint256 indexed tokenId, address seller);
    event DisputeStarted(uint256 indexed saleId, address indexed nftContract, uint256 indexed tokenId, address buyer);
    event DisputeResolved(uint256 indexed saleId, address indexed nftContract, uint256 indexed tokenId, address winner);

    constructor(address _platformWallet, address _stablecoinAddress) {
        platformWallet = _platformWallet;
        stablecoinAddress = _stablecoinAddress;
    }

    /**
     * @dev 列出NFT供出售
     * @param nftContract NFT合约地址
     * @param tokenId NFT的token ID
     * @param price 出售价格（Wei）
     */
    function listItem(address nftContract, uint256 tokenId, uint256 price) external nonReentrant {
        require(price > 0, "Price must be greater than 0");

        // 检查调用者是否是NFT所有者
        IERC721 nft = IERC721(nftContract);
        require(nft.ownerOf(tokenId) == msg.sender, "Not the owner of this NFT");

        // 检查NFT是否已被批准给市场合约
        require(nft.getApproved(tokenId) == address(this) || nft.isApprovedForAll(msg.sender, address(this)), "Marketplace is not approved to transfer this NFT");

        // 创建新交易
        saleCount++;
        sales[saleCount] = Sale({
            tokenId: tokenId,
            nftContract: nftContract,
            seller: msg.sender,
            buyer: address(0),
            price: price,
            status: SaleStatus.Active,
            createdAt: block.timestamp,
            updatedAt: block.timestamp,
            disputeEndTime: 0
        });

        emit ItemListed(saleCount, nftContract, tokenId, msg.sender, price);
    }

    /**
     * @dev 购买NFT
     * @param saleId 交易ID
     */
    function buyItem(uint256 saleId) external payable nonReentrant {
        Sale storage sale = sales[saleId];

        require(sale.status == SaleStatus.Active, "Item is not for sale");
        require(msg.value >= sale.price, "Insufficient funds sent");

        // 转移NFT到买家
        IERC721(sale.nftContract).safeTransferFrom(sale.seller, msg.sender, sale.tokenId);

        // 计算平台费用
        uint256 platformFee = (sale.price * platformFeePercentage) / 10000;

        // 计算版税
        uint256 royaltyAmount = 0;
        address royaltyReceiver = address(0);

        // 尝试获取版税信息
        try ArtBlockNFT(sale.nftContract).royaltyInfo(sale.tokenId, sale.price) returns (address receiver, uint256 amount) {
            royaltyReceiver = receiver;
            royaltyAmount = amount;
        } catch {
            // 如果合约不支持版税，版税为0
        }

        // 计算卖家实际收入
        uint256 sellerRevenue = sale.price - platformFee - royaltyAmount;

        // 支付版税
        if (royaltyAmount > 0 && royaltyReceiver != address(0)) {
            payable(royaltyReceiver).transfer(royaltyAmount);
        }

        // 支付卖家
        payable(sale.seller).transfer(sellerRevenue);

        // 支付平台费用
        payable(platformWallet).transfer(platformFee);

        // 更新交易状态
        sale.buyer = msg.sender;
        sale.status = SaleStatus.Completed;
        sale.updatedAt = block.timestamp;

        // 如果有退款，退还多余的ETH
        if (msg.value > sale.price) {
            payable(msg.sender).transfer(msg.value - sale.price);
        }

        emit ItemSold(saleId, sale.nftContract, sale.tokenId, sale.seller, msg.sender, sale.price);
    }

    /**
     * @dev 取消NFT出售
     * @param saleId 交易ID
     */
    function cancelSale(uint256 saleId) external nonReentrant {
        Sale storage sale = sales[saleId];

        require(sale.status == SaleStatus.Active, "Item is not active");
        require(msg.sender == sale.seller, "Only seller can cancel the sale");

        // 更新交易状态
        sale.status = SaleStatus.Canceled;
        sale.updatedAt = block.timestamp;

        emit ItemCanceled(saleId, sale.nftContract, sale.tokenId, msg.sender);
    }

    /**
     * @dev 发起交易争议
     * @param saleId 交易ID
     */
    function startDispute(uint256 saleId) external nonReentrant {
        Sale storage sale = sales[saleId];

        require(sale.status == SaleStatus.Completed, "Item must be completed to start dispute");
        require(msg.sender == sale.buyer, "Only buyer can start a dispute");
        require(block.timestamp < sale.updatedAt + disputePeriod, "Dispute period has expired");

        // 更新交易状态
        sale.status = SaleStatus.Dispute;
        sale.disputeEndTime = block.timestamp + disputePeriod;
        sale.updatedAt = block.timestamp;

        emit DisputeStarted(saleId, sale.nftContract, sale.tokenId, msg.sender);
    }

    /**
     * @dev 解决交易争议
     * @param saleId 交易ID
     * @param refundBuyer 是否退款给买家
     */
    function resolveDispute(uint256 saleId, bool refundBuyer) external nonReentrant onlyOwner {
        Sale storage sale = sales[saleId];

        require(sale.status == SaleStatus.Dispute, "No active dispute for this item");

        if (refundBuyer) {
            // 退还买家资金（简化实现，实际应用中可能需要更复杂的逻辑）
            payable(sale.buyer).transfer(sale.price);

            // 转移NFT回卖家
            IERC721(sale.nftContract).safeTransferFrom(sale.buyer, sale.seller, sale.tokenId);

            emit DisputeResolved(saleId, sale.nftContract, sale.tokenId, sale.buyer);
        } else {
            emit DisputeResolved(saleId, sale.nftContract, sale.tokenId, sale.seller);
        }

        // 更新交易状态
        sale.status = SaleStatus.Completed;
        sale.updatedAt = block.timestamp;
    }

    /**
     * @dev 获取指定NFT的所有交易记录
     * @param nftContract NFT合约地址
     * @param tokenId NFT的token ID
     * @return 交易记录数组
     */
    function getSalesForNFT(address nftContract, uint256 tokenId) external view returns (Sale[] memory) {
        uint256 count = 0;

        // 计算符合条件的交易数量
        for (uint256 i = 1; i <= saleCount; i++) {
            if (sales[i].nftContract == nftContract && sales[i].tokenId == tokenId) {
                count++;
            }
        }

        // 创建结果数组
        Sale[] memory result = new Sale[](count);
        uint256 index = 0;

        // 填充结果数组
        for (uint256 i = 1; i <= saleCount; i++) {
            if (sales[i].nftContract == nftContract && sales[i].tokenId == tokenId) {
                result[index] = sales[i];
                index++;
            }
        }

        return result;
    }

    /**
     * @dev 获取用户的所有购买记录
     * @param user 用户地址
     * @return 交易记录数组
     */
    function getPurchasesByUser(address user) external view returns (Sale[] memory) {
        uint256 count = 0;

        // 计算符合条件的交易数量
        for (uint256 i = 1; i <= saleCount; i++) {
            if (sales[i].buyer == user && sales[i].status == SaleStatus.Completed) {
                count++;
            }
        }

        // 创建结果数组
        Sale[] memory result = new Sale[](count);
        uint256 index = 0;

        // 填充结果数组
        for (uint256 i = 1; i <= saleCount; i++) {
            if (sales[i].buyer == user && sales[i].status == SaleStatus.Completed) {
                result[index] = sales[i];
                index++;
            }
        }

        return result;
    }

    /**
     * @dev 获取用户的所有出售记录
     * @param user 用户地址
     * @return 交易记录数组
     */
    function getSalesByUser(address user) external view returns (Sale[] memory) {
        uint256 count = 0;

        // 计算符合条件的交易数量
        for (uint256 i = 1; i <= saleCount; i++) {
            if (sales[i].seller == user && (sales[i].status == SaleStatus.Active || sales[i].status == SaleStatus.Completed)) {
                count++;
            }
        }

        // 创建结果数组
        Sale[] memory result = new Sale[](count);
        uint256 index = 0;

        // 填充结果数组
        for (uint256 i = 1; i <= saleCount; i++) {
            if (sales[i].seller == user && (sales[i].status == SaleStatus.Active || sales[i].status == SaleStatus.Completed)) {
                result[index] = sales[i];
                index++;
            }
        }

        return result;
    }

    /**
     * @dev 设置平台费用比例
     * @param newFeePercentage 新的平台费用比例，以0.01%为单位，例如200代表2%
     */
    function setPlatformFeePercentage(uint96 newFeePercentage) external onlyOwner {
        require(newFeePercentage <= 1000, "Fee percentage cannot exceed 10%");
        platformFeePercentage = newFeePercentage;
    }

    /**
     * @dev 设置争议期时长
     * @param newDisputePeriod 新的争议期时长（秒）
     */
    function setDisputePeriod(uint256 newDisputePeriod) external onlyOwner {
        disputePeriod = newDisputePeriod;
    }

    /**
     * @dev 设置平台收益地址
     * @param newPlatformWallet 新的平台收益地址
     */
    function setPlatformWallet(address newPlatformWallet) external onlyOwner {
        platformWallet = newPlatformWallet;
    }

    /**
     * @dev 设置稳定币地址
     * @param newStablecoinAddress 新的稳定币地址
     */
    function setStablecoinAddress(address newStablecoinAddress) external onlyOwner {
        stablecoinAddress = newStablecoinAddress;
    }

    /**
     * @dev 将平台收益兑换为稳定币（简化实现）
     * @param amount 要兑换的金额（Wei）
     */
    function convertPlatformRevenueToStablecoin(uint256 amount) external onlyOwner {
        // 这里应该实现将ETH兑换为稳定币的逻辑
        // 简化实现，实际应用中可能需要集成去中心化交易所
        emit PlatformRevenueConverted(amount, stablecoinAddress);
    }

    event PlatformRevenueConverted(uint256 amount, address stablecoin);
}

contracts/RoyaltyManager.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.10;

import "@openzeppelin/contracts/token/ERC721/IERC721.sol";
import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/security/ReentrancyGuard.sol";

/**
 * @title RoyaltyManager
 * @dev NFT市场版税管理合约，处理版税的设置、查询和分配
 */
contract RoyaltyManager is Ownable, ReentrancyGuard {
    // 版税信息结构
    struct RoyaltyInfo {
        address recipient;     // 版税接收者
        uint96 royaltyRate;    // 版税率，以0.01%为单位，例如200代表2%
    }

    // NFT合约地址 => token ID => 版税信息
    mapping(address => mapping(uint256 => RoyaltyInfo)) private tokenRoyalties;

    // NFT合约地址 => 合约级版税信息
    mapping(address => RoyaltyInfo) private contractRoyalties;

    // 允许的NFT合约列表
    mapping(address => bool) public allowedNFTContracts;

    // 事件
    event RoyaltySet(address indexed nftContract, uint256 indexed tokenId, address recipient, uint96 royaltyRate);
    event ContractRoyaltySet(address indexed nftContract, address recipient, uint96 royaltyRate);
    event NFTContractAllowed(address indexed nftContract, bool allowed);
    event RoyaltyPaid(address indexed nftContract, uint256 indexed tokenId, address recipient, uint256 amount);

    /**
     * @dev 设置特定NFT的版税信息
     * @param nftContract NFT合约地址
     * @param tokenId NFT的token ID
     * @param recipient 版税接收者地址
     * @param royaltyRate 版税率，以0.01%为单位，例如200代表2%
     */
    function setTokenRoyalty(
        address nftContract,
        uint256 tokenId,
        address recipient,
        uint96 royaltyRate
    ) external onlyOwner {
        require(allowedNFTContracts[nftContract], "NFT contract not allowed");
        require(royaltyRate <= 1000, "Royalty rate cannot exceed 10%");
        require(recipient != address(0), "Recipient address cannot be zero");

        tokenRoyalties[nftContract][tokenId] = RoyaltyInfo({
            recipient: recipient,
            royaltyRate: royaltyRate
        });

        emit RoyaltySet(nftContract, tokenId, recipient, royaltyRate);
    }

    /**
     * @dev 设置NFT合约级别的版税信息
     * @param nftContract NFT合约地址
     * @param recipient 版税接收者地址
     * @param royaltyRate 版税率，以0.01%为单位，例如200代表2%
     */
    function setContractRoyalty(
        address nftContract,
        address recipient,
        uint96 royaltyRate
    ) external onlyOwner {
        require(allowedNFTContracts[nftContract], "NFT contract not allowed");
        require(royaltyRate <= 1000, "Royalty rate cannot exceed 10%");
        require(recipient != address(0), "Recipient address cannot be zero");

        contractRoyalties[nftContract] = RoyaltyInfo({
            recipient: recipient,
            royaltyRate: royaltyRate
        });

        emit ContractRoyaltySet(nftContract, recipient, royaltyRate);
    }

    /**
     * @dev 允许或禁止NFT合约使用版税管理
     * @param nftContract NFT合约地址
     * @param allowed 是否允许
     */
    function allowNFTContract(address nftContract, bool allowed) external onlyOwner {
        allowedNFTContracts[nftContract] = allowed;
        emit NFTContractAllowed(nftContract, allowed);
    }

    /**
     * @dev 获取特定NFT的版税信息
     * @param nftContract NFT合约地址
     * @param tokenId NFT的token ID
     * @param salePrice 销售价格
     * @return recipient 版税接收者地址
     * @return royaltyAmount 版税金额
     */
    function getRoyaltyInfo(
        address nftContract,
        uint256 tokenId,
        uint256 salePrice
    ) public view returns (address recipient, uint256 royaltyAmount) {
        RoyaltyInfo memory tokenRoyalty = tokenRoyalties[nftContract][tokenId];

        // 如果特定NFT有版税设置，使用该设置
        if (tokenRoyalty.recipient != address(0)) {
            royaltyAmount = (salePrice * tokenRoyalty.royaltyRate) / 10000;
            return (tokenRoyalty.recipient, royaltyAmount);
        }

        // 否则使用合约级版税设置
        RoyaltyInfo memory contractRoyalty = contractRoyalties[nftContract];
        if (contractRoyalty.recipient != address(0)) {
            royaltyAmount = (salePrice * contractRoyalty.royaltyRate) / 10000;
            return (contractRoyalty.recipient, royaltyAmount);
        }

        // 如果都没有设置，返回0
        return (address(0), 0);
    }

    /**
     * @dev 支付版税
     * @param nftContract NFT合约地址
     * @param tokenId NFT的token ID
     * @param salePrice 销售价格
     * @return success 是否成功支付版税
     */
    function payRoyalty(
        address nftContract,
        uint256 tokenId,
        uint256 salePrice
    ) external payable nonReentrant returns (bool success) {
        (address recipient, uint256 royaltyAmount) = getRoyaltyInfo(nftContract, tokenId, salePrice);

        if (recipient == address(0) || royaltyAmount == 0) {
            return false;
        }

        require(msg.value >= royaltyAmount, "Insufficient funds sent for royalty");

        // 支付版税
        payable(recipient).transfer(royaltyAmount);

        // 如果有退款，退还多余的ETH
        if (msg.value > royaltyAmount) {
            payable(msg.sender).transfer(msg.value - royaltyAmount);
        }

        emit RoyaltyPaid(nftContract, tokenId, recipient, royaltyAmount);
        return true;
    }

    /**
     * @dev 提取合约中的ETH余额（紧急情况使用）
     */
    function emergencyWithdraw() external onlyOwner {
        payable(owner()).transfer(address(this).balance);
    }

    /**
     * @dev 合约接收ETH的fallback函数
     */
    receive() external payable {}
}

